                    $skipped++;
                    continue;
                }
                if ($qty > 0) {
                    $this->addStockForBranch($product, $branchId, $qty);
                    $stockAdded += $qty;
                }
                $this->refreshProductQty($product->fresh());
                $created++;
            }
        });

        fclose($handle);

        return response()->json(['summary' => [
            'created' => $created,
            'updated' => $updated,
            'skipped' => $skipped,
            'stockAdded' => $stockAdded,
            'errors' => $errors,
